css:
.loader {color: var(--loader-color, #f97316);
  --loader-secondary-color: #facc15;
  --loader-bg: #ffffff;
  width: 80px;
  aspect-ratio: 1;
  position: relative;
}.loader:before,.loader:after {content: "";
  position: absolute;
  inset: 0;
  background: var(--loader-color, #f97316);
  box-shadow: 0 0 0 50px;
  clip-path: polygon(50% 0%, 61% 35%, 98% 35%, 68% 57%, 79% 91%, 50% 70%, 21% 91%, 32% 57%, 2% 35%, 39% 35%);
}.loader:before {animation: l5 1s infinite;
  transform: perspective(300px) translateZ(0px)}@keyframes l5 {to {transform: perspective(300px) translateZ(150px);
  opacity:0}}
